#!/usr/bin/env node
/**
 * Knowledge Graph Validation Script
 * Performs comprehensive validation of the Understand Anything knowledge graph.
 */

const fs = require('fs');

const VALID_NODE_TYPES = [
  'file', 'function', 'class', 'module', 'concept', 'config',
  'document', 'service', 'table', 'endpoint', 'pipeline', 'schema',
  'resource', 'domain', 'flow', 'step'
];

const VALID_EDGE_TYPES = [
  'imports', 'exports', 'contains', 'inherits', 'implements', 'calls',
  'subscribes', 'publishes', 'middleware', 'reads_from', 'writes_to',
  'transforms', 'validates', 'depends_on', 'tested_by', 'configures',
  'related', 'similar_to', 'deploys', 'serves', 'migrates', 'documents',
  'provisions', 'routes', 'defines_schema', 'triggers', 'contains_flow',
  'flow_step', 'cross_domain'
];

const VALID_DIRECTIONS = ['forward', 'backward', 'bidirectional'];

const FILE_LEVEL_TYPES = [
  'file', 'config', 'document', 'service', 'pipeline',
  'table', 'schema', 'resource', 'endpoint'
];

const NODE_PREFIX_MAP = {
  'file': 'file:', 'function': 'function:', 'class': 'class:',
  'module': 'module:', 'concept': 'concept:', 'config': 'config:',
  'document': 'document:', 'service': 'service:', 'table': 'table:',
  'endpoint': 'endpoint:', 'pipeline': 'pipeline:', 'schema': 'schema:',
  'resource': 'resource:', 'domain': 'domain:', 'flow': 'flow:', 'step': 'step:'
};

function main() {
  const inputPath = process.argv[2];
  const outputPath = process.argv[3];

  if (!inputPath || !outputPath) {
    console.error('Usage: node ua-graph-validate.js <input-json> <output-json>') >&2;
    process.exit(1);
  }

  let graph;
  try {
    const content = fs.readFileSync(inputPath, 'utf8');
    graph = JSON.parse(content);
  } catch (err) {
    console.error('Failed to read or parse JSON file:', err.message);
    process.exit(1);
  }

  const issues = [];
  const warnings = [];
  const stats = {
    totalNodes: 0,
    totalEdges: 0,
    totalLayers: 0,
    tourSteps: 0,
    nodeTypes: {},
    edgeTypes: {}
  };

  // Build set of all node IDs for reference checks
  const nodeIds = new Set();
  const nodeMap = new Map();

  // === PHASE 1: Schema Validation ===

  // Validate nodes
  if (!Array.isArray(graph.nodes)) {
    issues.push('Missing or invalid "nodes" array in graph');
  } else {
    stats.totalNodes = graph.nodes.length;

    graph.nodes.forEach((node, idx) => {
      // Check required fields
      if (!node.id || typeof node.id !== 'string' || node.id.trim() === '') {
        issues.push(`Node at index ${idx} has missing or empty id`);
      }
      if (!node.type || typeof node.type !== 'string') {
        issues.push(`Node at index ${idx} (${node.id || 'unknown'}) has missing or invalid type`);
      } else if (!VALID_NODE_TYPES.includes(node.type)) {
        issues.push(`Node at index ${idx} (${node.id}) has invalid type "${node.type}"`);
      }
      if (!node.name || typeof node.name !== 'string' || node.name.trim() === '') {
        issues.push(`Node at index ${idx} (${node.id || 'unknown'}) has missing or empty name`);
      }
      if (!node.summary || typeof node.summary !== 'string' || node.summary.trim() === '') {
        issues.push(`Node at index ${idx} (${node.id || 'unknown'}) has missing or empty summary`);
      }
      if (!Array.isArray(node.tags) || node.tags.length === 0) {
        issues.push(`Node at index ${idx} (${node.id || 'unknown'}) has missing or empty tags array`);
      } else {
        const invalidTags = node.tags.filter(t => typeof t !== 'string' || t !== t.toLowerCase() || t.includes('_'));
        if (invalidTags.length > 0) {
          issues.push(`Node at index ${idx} (${node.id || 'unknown'}) has invalid tags: ${invalidTags.join(', ')} (must be lowercase hyphenated)`);
        }
      }
      if (!node.complexity || typeof node.complexity !== 'string' ||
          !['simple', 'moderate', 'complex'].includes(node.complexity)) {
        issues.push(`Node at index ${idx} (${node.id || 'unknown'}) has missing or invalid complexity`);
      }

      // Track for referential integrity
      if (node.id) {
        if (nodeIds.has(node.id)) {
          issues.push(`Duplicate node ID "${node.id}" found at index ${idx}`);
        } else {
          nodeIds.add(node.id);
          nodeMap.set(node.id, node);
        }
      }

      // Track type counts
      if (node.type) {
        stats.nodeTypes[node.type] = (stats.nodeTypes[node.type] || 0) + 1;
      }

      // Check ID prefix matches type
      if (node.id && node.type) {
        const expectedPrefix = NODE_PREFIX_MAP[node.type];
        if (expectedPrefix && !node.id.startsWith(expectedPrefix)) {
          warnings.push(`Node "${node.id}" has type "${node.type}" but ID should start with "${expectedPrefix}"`);
        }
      }
    });
  }

  // Validate edges
  if (!Array.isArray(graph.edges)) {
    issues.push('Missing or invalid "edges" array in graph');
  } else {
    stats.totalEdges = graph.edges.length;

    graph.edges.forEach((edge, idx) => {
      if (!edge.source || typeof edge.source !== 'string' || edge.source.trim() === '') {
        issues.push(`Edge at index ${idx} has missing or empty source`);
      }
      if (!edge.target || typeof edge.target !== 'string' || edge.target.trim() === '') {
        issues.push(`Edge at index ${idx} has missing or empty target`);
      }
      if (!edge.type || typeof edge.type !== 'string') {
        issues.push(`Edge at index ${idx} has missing or invalid type`);
      } else if (!VALID_EDGE_TYPES.includes(edge.type)) {
        issues.push(`Edge at index ${idx} has invalid type "${edge.type}"`);
      }
      if (!edge.direction || !VALID_DIRECTIONS.includes(edge.direction)) {
        issues.push(`Edge at index ${idx} has missing or invalid direction`);
      }
      if (typeof edge.weight !== 'number' || edge.weight < 0.0 || edge.weight > 1.0) {
        issues.push(`Edge at index ${idx} has missing or invalid weight (must be 0.0-1.0)`);
      }

      // Track edge type counts
      if (edge.type) {
        stats.edgeTypes[edge.type] = (stats.edgeTypes[edge.type] || 0) + 1;
      }
    });
  }

  // === PHASE 2: Referential Integrity ===

  graph.edges?.forEach((edge, idx) => {
    if (edge.source && !nodeIds.has(edge.source)) {
      issues.push(`Edge at index ${idx} references non-existent source node "${edge.source}"`);
    }
    if (edge.target && !nodeIds.has(edge.target)) {
      issues.push(`Edge at index ${idx} references non-existent target node "${edge.target}"`);
    }
  });

  // Check layers
  if (!Array.isArray(graph.layers)) {
    issues.push('Missing or invalid "layers" array in graph');
  } else {
    stats.totalLayers = graph.layers.length;

    graph.layers.forEach((layer, layerIdx) => {
      if (!layer.nodeIds || !Array.isArray(layer.nodeIds)) {
        issues.push(`Layer at index ${layerIdx} has missing or invalid nodeIds array`);
      } else {
        layer.nodeIds.forEach(nodeId => {
          if (!nodeIds.has(nodeId)) {
            issues.push(`Layer at index ${layerIdx} references non-existent node "${nodeId}"`);
          }
        });
      }
    });
  }

  // Check tour
  if (graph.tour && Array.isArray(graph.tour.steps)) {
    stats.tourSteps = graph.tour.steps.length;

    graph.tour.steps.forEach((step, stepIdx) => {
      if (step.nodeIds && Array.isArray(step.nodeIds)) {
        step.nodeIds.forEach(nodeId => {
          if (!nodeIds.has(nodeId)) {
            issues.push(`Tour step at index ${stepIdx} references non-existent node "${nodeId}"`);
          }
        });
      }
    });
  }

  // === PHASE 3: Completeness ===

  if (stats.totalNodes === 0) {
    issues.push('Graph contains zero nodes');
  }
  if (stats.totalEdges === 0) {
    issues.push('Graph contains zero edges');
  }

  // Detect domain graph
  const isDomainGraph = graph.nodes?.some(n =>
    ['domain', 'flow', 'step'].includes(n.type)
  );

  if (!isDomainGraph) {
    if (stats.totalLayers === 0) {
      issues.push('Graph contains zero layers');
    }
    if (!graph.tour || !graph.tour.steps || graph.tour.steps.length === 0) {
      issues.push('Graph contains zero tour steps');
    }
  } else {
    // Domain graph - relaxed requirements
    if (stats.totalLayers === 0) {
      warnings.push('Domain graph has zero layers (warning only for domain graphs)');
    }
    if (!graph.tour || !graph.tour.steps || graph.tour.steps.length === 0) {
      warnings.push('Domain graph has zero tour steps (warning only for domain graphs)');
    }
  }

  // === PHASE 4: Layer Coverage ===

  if (!isDomainGraph || stats.totalLayers > 0) {
    const fileLevelNodeIds = new Set();
    graph.nodes?.forEach(node => {
      if (FILE_LEVEL_TYPES.includes(node.type)) {
        fileLevelNodeIds.add(node.id);
      }
    });

    const layerNodeIdCounts = new Map();
    graph.layers?.forEach((layer, layerIdx) => {
      if (!layer.nodeIds || layer.nodeIds.length === 0) {
        issues.push(`Layer at index ${layerIdx} has empty nodeIds array`);
      }
      layer.nodeIds?.forEach(nodeId => {
        if (FILE_LEVEL_TYPES.includes(nodeMap.get(nodeId)?.type)) {
          layerNodeIdCounts.set(nodeId, (layerNodeIdCounts.get(nodeId) || 0) + 1);
        }
      });
    });

    // Check for file-level nodes missing from all layers
    fileLevelNodeIds.forEach(nodeId => {
      const count = layerNodeIdCounts.get(nodeId) || 0;
      if (count === 0) {
        issues.push(`File-level node "${nodeId}" does not appear in any layer`);
      } else if (count > 1) {
        issues.push(`File-level node "${nodeId}" appears in multiple layers (${count} times)`);
      }
    });
  }

  // === PHASE 5: Uniqueness (already checked in schema validation) ===

  // === PHASE 6: Tour Validation ===

  if (graph.tour && graph.tour.steps) {
    const stepCount = graph.tour.steps.length;
    if (stepCount < 5 || stepCount > 15) {
      warnings.push(`Tour has ${stepCount} steps (should be between 5 and 15)`);
    }

    const orders = graph.tour.steps.map(s => s.order).filter(o => typeof o === 'number');
    const uniqueOrders = new Set(orders);
    if (orders.length !== uniqueOrders.size) {
      warnings.push('Tour steps have duplicate order values');
    }

    const expectedOrders = Array.from({length: stepCount}, (_, i) => i + 1);
    const missingOrders = expectedOrders.filter(o => !orders.includes(o));
    if (missingOrders.length > 0 && orders.length > 0) {
      warnings.push(`Tour steps have non-sequential orders, missing: ${missingOrders.join(', ')}`);
    }

    graph.tour.steps.forEach((step, idx) => {
      if (!step.nodeIds || step.nodeIds.length === 0) {
        warnings.push(`Tour step at index ${idx} has empty nodeIds`);
      }
    });
  }

  // === PHASE 7: Quality Checks ===

  // Self-referencing edges
  graph.edges?.forEach((edge, idx) => {
    if (edge.source === edge.target) {
      warnings.push(`Edge at index ${idx} is self-referencing (source equals target)`);
    }
  });

  // Orphan nodes
  const connectedNodes = new Set();
  graph.edges?.forEach(edge => {
    if (edge.source) connectedNodes.add(edge.source);
    if (edge.target) connectedNodes.add(edge.target);
  });

  const orphanNodes = [];
  graph.nodes?.forEach(node => {
    if (!connectedNodes.has(node.id)) {
      orphanNodes.push(node.id);
    }
  });
  if (orphanNodes.length > 0) {
    warnings.push(`${orphanNodes.length} node(s) have no edges connecting to them: ${orphanNodes.slice(0, 5).join(', ')}${orphanNodes.length > 5 ? '...' : ''}`);
  }

  // Generic summaries
  graph.nodes?.forEach(node => {
    if (node.summary && node.name) {
      const summaryLower = node.summary.toLowerCase();
      const nameLower = node.name.toLowerCase();
      if (node.summary === node.name ||
          (node.filePath && node.summary.toLowerCase().includes(node.filePath.toLowerCase())) ||
          (node.summary.length < 20)) {
        warnings.push(`Node "${node.id}" has a generic or very short summary`);
      }
    }
  });

  // === PHASE 8: Non-Code Node Quality Checks ===

  const nodeEdgeCounts = new Map();
  graph.edges?.forEach(edge => {
    if (!nodeEdgeCounts.has(edge.source)) nodeEdgeCounts.set(edge.source, []);
    if (!nodeEdgeCounts.has(edge.target)) nodeEdgeCounts.set(edge.target, []);
    nodeEdgeCounts.get(edge.source).push(edge.type);
    nodeEdgeCounts.get(edge.target).push(edge.type);
  });

  graph.nodes?.forEach(node => {
    const edges = nodeEdgeCounts.get(node.id) || [];
    switch (node.type) {
      case 'document':
        if (!edges.includes('documents')) {
          warnings.push(`Document node "${node.id}" has no 'documents' edges`);
        }
        break;
      case 'service':
        if (!edges.includes('deploys') && !edges.includes('depends_on')) {
          warnings.push(`Service node "${node.id}" has no 'deploys' or 'depends_on' edges`);
        }
        break;
      case 'pipeline':
        if (!edges.includes('triggers')) {
          warnings.push(`Pipeline node "${node.id}" has no 'triggers' edges`);
        }
        break;
      case 'table':
        if (!edges.includes('migrates') && !edges.includes('defines_schema')) {
          warnings.push(`Table node "${node.id}" has no 'migrates' or 'defines_schema' edges`);
        }
        break;
      case 'schema':
        if (!edges.includes('defines_schema')) {
          warnings.push(`Schema node "${node.id}" has no 'defines_schema' edges`);
        }
        break;
      case 'domain':
        if (!edges.includes('contains_flow')) {
          warnings.push(`Domain node "${node.id}" has no 'contains_flow' edges`);
        }
        break;
      case 'flow':
        if (!edges.includes('flow_step')) {
          warnings.push(`Flow node "${node.id}" has no 'flow_step' edges`);
        }
        break;
    }
  });

  // === Output Results ===

  const result = {
    scriptCompleted: true,
    issues,
    warnings,
    stats
  };

  try {
    fs.writeFileSync(outputPath, JSON.stringify(result, null, 2));
  } catch (err) {
    console.error('Failed to write output file:', err.message);
    process.exit(1);
  }

  console.error(`Validation complete. Issues: ${issues.length}, Warnings: ${warnings.length}`);
}

main();

