  // === PHASE 5: Uniqueness (already checked in schema validation) ===

  // === PHASE 6: Tour Validation ===

  if (graph.tour && graph.tour.steps) {
    const stepCount = graph.tour.steps.length;
    if (stepCount < 5 || stepCount > 15) {
      warnings.push(`Tour has ${stepCount} steps (should be between 5 and 15)`);
    }

    const orders = graph.tour.steps.map(s => s.order).filter(o => typeof o === 'number');
    const uniqueOrders = new Set(orders);
    if (orders.length !== uniqueOrders.size) {
      warnings.push('Tour steps have duplicate order values');
    }

    const expectedOrders = Array.from({length: stepCount}, (_, i) => i + 1);
    const missingOrders = expectedOrders.filter(o => !orders.includes(o));
    if (missingOrders.length > 0 && orders.length > 0) {
      warnings.push(`Tour steps have non-sequential orders, missing: ${missingOrders.join(', ')}`);
    }

    graph.tour.steps.forEach((step, idx) => {
      if (!step.nodeIds || step.nodeIds.length === 0) {
        warnings.push(`Tour step at index ${idx} has empty nodeIds`);
      }
    });
  }

  // === PHASE 7: Quality Checks ===

  // Self-referencing edges
  graph.edges?.forEach((edge, idx) => {
    if (edge.source === edge.target) {
      warnings.push(`Edge at index ${idx} is self-referencing (source equals target)`);
    }
  });

  // Orphan nodes
  const connectedNodes = new Set();
  graph.edges?.forEach(edge => {
    if (edge.source) connectedNodes.add(edge.source);
    if (edge.target) connectedNodes.add(edge.target);
  });

  const orphanNodes = [];
  graph.nodes?.forEach(node => {
    if (!connectedNodes.has(node.id)) {
      orphanNodes.push(node.id);
    }
  });
  if (orphanNodes.length > 0) {
    warnings.push(`${orphanNodes.length} node(s) have no edges connecting to them: ${orphanNodes.slice(0, 5).join(', ')}${orphanNodes.length > 5 ? '...' : ''}`);
  }

  // Generic summaries
  graph.nodes?.forEach(node => {
    if (node.summary && node.name) {
      if (node.summary === node.name ||
          (node.filePath && node.summary.toLowerCase().includes(node.filePath.toLowerCase())) ||
          (node.summary.length < 20)) {
        warnings.push(`Node "${node.id}" has a generic or very short summary`);
      }
    }
  });

  // === PHASE 8: Non-Code Node Quality Checks ===

  const nodeEdgeCounts = new Map();
  graph.edges?.forEach(edge => {
    if (!nodeEdgeCounts.has(edge.source)) nodeEdgeCounts.set(edge.source, []);
    if (!nodeEdgeCounts.has(edge.target)) nodeEdgeCounts.set(edge.target, []);
    nodeEdgeCounts.get(edge.source).push(edge.type);
    nodeEdgeCounts.get(edge.target).push(edge.type);
  });

  graph.nodes?.forEach(node => {
    const edges = nodeEdgeCounts.get(node.id) || [];
    switch (node.type) {
      case 'document':
        if (!edges.includes('documents')) {
          warnings.push(`Document node "${node.id}" has no 'documents' edges`);
        }
        break;
      case 'service':
        if (!edges.includes('deploys') && !edges.includes('depends_on')) {
          warnings.push(`Service node "${node.id}" has no 'deploys' or 'depends_on' edges`);
        }
        break;
      case 'pipeline':
        if (!edges.includes('triggers')) {
          warnings.push(`Pipeline node "${node.id}" has no 'triggers' edges`);
        }
        break;
      case 'table':
        if (!edges.includes('migrates') && !edges.includes('defines_schema')) {
          warnings.push(`Table node "${node.id}" has no 'migrates' or 'defines_schema' edges`);
        }
        break;
      case 'schema':
        if (!edges.includes('defines_schema')) {
          warnings.push(`Schema node "${node.id}" has no 'defines_schema' edges`);
        }
        break;
      case 'domain':
        if (!edges.includes('contains_flow')) {
          warnings.push(`Domain node "${node.id}" has no 'contains_flow' edges`);
        }
        break;
      case 'flow':
        if (!edges.includes('flow_step')) {
          warnings.push(`Flow node "${node.id}" has no 'flow_step' edges`);
        }
        break;
    }
  });

  // === Output Results ===

  const result = {
    scriptCompleted: true,
    issues,
    warnings,
    stats
  };

  try {
    fs.writeFileSync(outputPath, JSON.stringify(result, null, 2));
  } catch (err) {
    console.error('Failed to write output file:', err.message);
    process.exit(1);
  }

  console.error(`Validation complete. Issues: ${issues.length}, Warnings: ${warnings.length}`);
}

main();
VALIDATION_SCRIPT_EOF
echo "Script created successfully"
